VALUES
  ('diplomatic-36ccc47a-moex-00620', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '美、中兩國1972年所簽訂的「上海公報」中，下列那一項並非其重點內容？', '["美中關係正常化符合兩國利益", "美國認知一個中國原則，臺灣屬於中國的一部分", "美國將階段性削減駐臺軍隊及軍事設施", "美國將終止與臺灣簽訂的共同防禦條約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00621', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '2021年7月1日，中共中央總書記習近平於《中共建黨百年》講話中主張要堅持一個中國原則和「九二共 識」，推進祖國和平統一進程。其實，習近平早在2019年1月2日《告臺灣同胞書》發表40周年紀念活 動發表談話時，就提出了「兩岸同屬一個中國，共同努力謀求國家統一」的九二共識。試問下列何者非習 近平的主張？', '["九二共識容許一中各表", "「和平統一、一國兩制」是實現國家統一的最佳方式", "制度不同，不是統一的障礙，更不是分裂的藉口。「一國兩制」的提出，本來就是為了照顧臺灣現實情 況，維護臺灣同胞利益福祉", "世界上只有一個中國，堅持一個中國原則是公認的國際關係準則，是國際社會普遍共識"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00622', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '「統一戰線」（或稱「統戰」）是中國共產黨的重要統治方式。請問關於「統一戰線」，下列何者錯誤？', '["2006年中共發布「關於鞏固和壯大新世紀新階段統一戰線的意見」，指出目前的統戰工作對象包括私營 企業與外資企業的管理技術人員", "根據憲法序言，中國人民政治協商會議是有廣泛代表性的統一戰線組織", "國務院內設有統戰部，由習近平直接領導", "統一戰線的說法，曾出現在列寧的著作中"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00623', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '中共政府經常召開眾多類型的黨政會議，請問「四中全會」所指為何？', '["全國人民代表大會中央委員會第4次全體會議", "中央人民政府第4次全體會議", "中國人民政治協商第4次全體會議", "中國共產黨中央委員會第4次全體會議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00624', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '大陸地區人民經許可入境臺灣地區，從事與許可目的不符之活動，且有危害公共秩序的急迫考量，應如何 處理？', '["應直接報請大陸委員會處理", "國家安全局應遴聘有關機關代表，召開審查會，由國家安全局強制出境", "得不經審查會審查，由內政部移民署強制出境", "應直接報請海峽交流基金會強制出境"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
